sql.where:
f.deleted_at is null

  and (lower(f.filename) like #{keyword} or lower(f.original_name) like #{keyword})

and lower(f.file_type) like #{fileTypeLike}
and  = #{status}
and f.upload_type = #{uploadType}
and f.file_size >= #{minSize}
and f.file_size <= #{maxSize}
and f.upload_time >= #{start}
and f.upload_time < #{end}

