  storage_object_key, storage_domain, storage_prefix
)
values (
  #{filename}, #{originalName}, #{fileUrl}, #{fileType}, #{fileSize}, #{uploadType},
  #{uploadedBy}, #{checksumSha256}, #{storageProvider}, #{storageBucket}, #{storageRegion},
  #{storageObjectKey}, #{storageDomain}, #{storagePrefix}
)

mapper.select:
select id, file_url, bound_comment_id
from files
where deleted_at is null
  and uploaded_by = #{userId}
  and upload_type = #{uploadType}
  and bound_comment_id is null
  and upload_time >= current_timestamp - interval '1' day
  and file_url in

    #{fileUrl}

mapper.update:
update files
set bound_comment_id = #{commentId}, bound_at = current_timestamp
where deleted_at is null
  and uploaded_by = #{userId}
  and upload_type = #{uploadType}
  and bound_comment_id is null
  and file_url in

    #{fileUrl}
